+
+    // Readers
+    for _ in 0..5 {
+        let path = Arc::clone(&path);
+        let handle = thread::spawn(move || {
+            let store = HistoryStore::open(&path).expect("open");
+            let _ = store.get_latest_all().expect("read");
+        });
+        handles.push(handle);
+    }
+
+    for h in handles {
+        h.join().expect("join");
+    }
+}
